<template>
  <view class="container">
    <!-- 头部 -->
    <view class="header">
      <view>
        <text class="title">用户授权管理</text>
        <text class="subtitle">共 {{ userList.length }} 位用户</text>
      </view>
      <button class="btn-add" @click="openAddModal">添加用户</button>
    </view>
    
    <!-- 用户列表 -->
    <scroll-view scroll-y class="user-list" enable-back-to-top>
      <view 
        v-for="item in userList" 
        :key="item._id" 
        class="user-item fade-in"
      >
        <view class="user-info">
          <view class="avatar-placeholder">{{ item.name ? item.name[0] : '无' }}</view>
          <view class="info-content">
            <text class="name">{{ item.name || '未命名' }}</text>
            <view class="phone-row">
              <text class="phone">{{ item.phone || '无手机号' }}</text>
              <text :class="['bind-status', item.openid ? 'bound' : '']">
                {{ item.openid ? '已绑定微信' : '未绑定' }}
              </text>
            </view>
            <view class="roles-tag">
              <text 
                v-for="role in (item.authorized_roles || [item.role])" 
                :key="role" 
                class="tag"
              >
                {{ role }}
              </text>
            </view>
          </view>
        </view>
        
        <view class="action-btn-group">
          <view class="action-btn edit" @click="openEditModal(item)">
            <text>编辑</text>
          </view>
          <view 
            v-if="item.openid" 
            class="action-btn unbind" 
            @click="unbindWechat(item)"
          >
            <text>解绑</text>
          </view>
          <view 
            v-if="canDelete(item)" 
            class="action-btn delete" 
            @click="deleteUser(item)"
          >
            <text>删除</text>
          </view>
        </view>
      </view>
    </scroll-view>
    
    <!-- 添加/编辑弹窗 -->
    <view v-if="showModal" class="modal-mask" @click="closeModal">
      <view class="modal-content" @click.stop>
        <view class="modal-header">
          <text class="modal-title">{{ isEdit ? '编辑用户' : '添加用户' }}</text>
        </view>
        
        <view class="form-item">
          <text class="label">手机号</text>
          <input 
            class="input" 
            placeholder="请输入手机号" 
            type="number" 
            maxlength="11"
            v-model="form.phone"
          />
        </view>
        
        <view class="form-item">
          <text class="label">姓名</text>
          <input 
            class="input" 
            placeholder="请输入姓名" 
            v-model="form.name"
          />
        </view>
        
        <view class="form-item">
          <text class="label">授权角色 (多选)</text>
          <checkbox-group @change="onRoleChange" class="role-group">
            <label 
              v-for="role in roleOptions" 
              :key="role" 
              class="role-label"
            >
              <checkbox 
                :value="role" 
                :checked="form.roles.includes(role)"
                color="#1677ff"
              />
              <text>{{ role }}</text>
            </label>
          </checkbox-group>
        </view>
        
        <view class="modal-footer">
          <button class="btn-cancel" @click="closeModal">取消</button>
          <button class="btn-confirm" @click="submitForm">确定</button>
        </view>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref, reactive, computed, onMounted } from 'vue'
import { useUserStore } from '@/store/user'

const userStore = useUserStore()

const userList = ref([])
const loading = ref(false)
const showModal = ref(false)
const isEdit = ref(false)

const roleOptions = ['派出所', '街道', '社区', '管理员']

// 是否是超级管理员（根据手机号判断）
const isSuperAdmin = computed(() => {
  return userStore.phone === '18926249923'
})

const form = reactive({
  id: '',
  phone: '',
  name: '',
  roles: []
})

onMounted(() => {
  loadUserList()
})

// 加载用户列表
const loadUserList = async () => {
  uni.showLoading({ title: '加载中...' })
  try {
    const { result } = await uniCloud.callFunction({
      name: 'adminManager',
      data: {
        action: 'getUserList'
      }
    })
    
    if (result.success) {
      userList.value = result.data
    }
  } catch (error) {
    uni.showToast({
      title: '加载失败',
      icon: 'none'
    })
  } finally {
    uni.hideLoading()
  }
}

// 打开添加弹窗
const openAddModal = () => {
  isEdit.value = false
  form.id = ''
  form.phone = ''
  form.name = ''
  form.roles = []
  showModal.value = true
}

// 打开编辑弹窗
const openEditModal = (item) => {
  isEdit.value = true
  form.id = item._id
  form.phone = item.phone || ''
  form.name = item.name || ''
  form.roles = item.authorized_roles || (item.role ? [item.role] : [])
  showModal.value = true
}

// 关闭弹窗
const closeModal = () => {
  showModal.value = false
}

// 角色选择变化
const onRoleChange = (e) => {
  form.roles = e.detail.value
}

// 判断是否可以删除用户
const canDelete = (item) => {
  // 管理员不能删除其他管理员，除非自己是超级管理员
  if (item.authorized_roles && item.authorized_roles.includes('管理员')) {
    return isSuperAdmin.value
  }
  return true
}

// 提交表单
const submitForm = async () => {
  if (!form.phone || form.roles.length === 0) {
    uni.showToast({
      title: '请填写手机号并选择角色',
      icon: 'none'
    })
    return
  }
  
  uni.showLoading({ title: '提交中...' })
  
  try {
    const action = isEdit.value ? 'updateUser' : 'addUser'
    const params = {
      phone: form.phone,
      name: form.name,
      roles: form.roles
    }
    
    if (isEdit.value) {
      params.userId = form.id
    }
    
    const { result } = await uniCloud.callFunction({
      name: 'adminManager',
      data: {
        action,
        params
      }
    })
    
    if (result.success) {
      uni.showToast({
        title: isEdit.value ? '更新成功' : '添加成功'
      })
      closeModal()
      loadUserList()
    } else {
      uni.showToast({
        title: result.error || '操作失败',
        icon: 'none'
      })
    }
  } catch (error) {
    uni.showToast({
      title: '系统异常',
      icon: 'none'
    })
  } finally {
    uni.hideLoading()
  }
}

// 解绑微信
const unbindWechat = (item) => {
  uni.showModal({
    title: '解绑确认',
    content: `确定要解除 "${item.name}" 的微信绑定吗？解绑后该用户可以使用任意微信重新绑定登录。`,
    success: async (res) => {
      if (res.confirm) {
        uni.showLoading({ title: '处理中...' })
        
        try {
          const { result } = await uniCloud.callFunction({
            name: 'adminManager',
            data: {
              action: 'unbindWechat',
              params: {
                userId: item._id
              }
            }
          })
          
          if (result.success) {
            uni.showToast({
              title: '解绑成功',
              icon: 'success'
            })
            loadUserList()
          } else {
            uni.showToast({
              title: result.error || '解绑失败',
              icon: 'none'
            })
          }
        } catch (error) {
          uni.showToast({
            title: '系统异常',
            icon: 'none'
          })
        } finally {
          uni.hideLoading()
        }
      }
    }
  })
}

// 删除用户
const deleteUser = (item) => {
  uni.showModal({
    title: '删除确认',
    content: `确定要删除用户 "${item.name}" 吗？此操作不可恢复。`,
    confirmColor: '#ff4d4f',
    success: async (res) => {
      if (res.confirm) {
        uni.showLoading({ title: '删除中...' })
        
        try {
          const { result } = await uniCloud.callFunction({
            name: 'adminManager',
            data: {
              action: 'deleteUser',
              params: {
                userId: item._id
              }
            }
          })
          
          if (result.success) {
            uni.showToast({
              title: '删除成功',
              icon: 'success'
            })
            loadUserList()
          } else {
            uni.showToast({
              title: result.error || '删除失败',
              icon: 'none'
            })
          }
        } catch (error) {
          uni.showToast({
            title: '系统异常',
            icon: 'none'
          })
        } finally {
          uni.hideLoading()
        }
      }
    }
  })
}
</script>

